const input = $input.first().json;

return [{
  json: {
    customer_id: String(input.customer_id ?? input.user_id ?? input.userId ?? 'inconnu'),
    customer_message: String(input.customer_message ?? input.message ?? 'Message non fourni'),
    reason: String(input.reason ?? 'Intervention humaine demandée par l’Agent IA'),
    session_id: String(input.session_id ?? ''),
    requested_at: new Date().toISOString()
  }
}];

const handoff = $('Préparer transfert').first().json;

return [{
  json: {
    success: true,
    handoff: true,
    customer_id: handoff.customer_id,
    reason: handoff.reason,
    response: 'Je vous transfère à un conseiller humain. Il vous répondra dès que possible.'
  }
}];
